/**
 * Client-side search with Fuse.js
 * Fuse.js loaded via CDN. Search index generated by Hugo as /search.json.
 *
 * Keyboard shortcuts:
 *   Ctrl+K / Cmd+K  → Open/focus search
 *   /               → Open/focus search (ignored when in input/textarea/contenteditable)
 *   Escape          → Close search overlay
 *   ArrowUp/Down    → Navigate results
 *   Enter           → Open selected result
 *   Tab             → Cycle focus within overlay (focus trap)
 */
(function () {
  'use strict';

  var CONFIG = {
    fuseKeys: ['title', 'summary', 'tags'],
    fuseThreshold: 0.4,
    minChars: 2,
    debounceMs: 200,
    fuseJsURL: 'https://cdn.jsdelivr.net/npm/fuse.js@7.0.0/dist/fuse.min.js',
    indexURL: '/search.json',
  };

  var fuse = null;
  var searchIndex = [];
  var currentResults = [];
  var activeIndex = -1;
  var isLoadingFuse = false;
  var fuseLoadCallbacks = [];

  var overlay = document.getElementById('cd-search');
  var input = document.getElementById('cd-search-input');
  var resultsContainer = overlay && overlay.querySelector('.cd-search-results');
  var statusContainer = overlay && overlay.querySelector('.cd-search-status');
  var closeBtn = overlay && overlay.querySelector('.cd-search-close');

  // --- Utilities ---

  /** Debounce helper */
  function debounce(fn, ms) {
    var timer = null;
    return function () {
      var ctx = this;
      var args = arguments;
      clearTimeout(timer);
      timer = setTimeout(function () {
        fn.apply(ctx, args);
      }, ms);
    };
  }

  /** Check if we're inside a text input (to skip '/' shortcut) */
  function isTextInput(el) {
    var tag = el && el.tagName;
    return tag === 'INPUT' || tag === 'TEXTAREA' || (el && el.isContentEditable);
  }

  /** Get all focusable elements inside the overlay */
  function getFocusableElements() {
    if (!overlay) return [];
    var selectors =
      'a[href], button:not([disabled]), input:not([disabled]), [tabindex]:not([tabindex="-1"])';
    return Array.prototype.slice.call(overlay.querySelectorAll(selectors));
  }

  // --- Fuse.js Loading ---

  /** Load Fuse.js from CDN if not already loaded */
  function loadFuseJS(callback) {
    if (typeof Fuse !== 'undefined') {
      if (callback) callback();
      return;
    }

    if (isLoadingFuse) {
      if (callback) fuseLoadCallbacks.push(callback);
      return;
    }

    isLoadingFuse = true;
    var script = document.createElement('script');
    script.src = CONFIG.fuseJsURL;
    script.async = true;

    script.onload = function () {
      isLoadingFuse = false;
      if (callback) callback();
      fuseLoadCallbacks.forEach(function (cb) {
        cb();
      });
      fuseLoadCallbacks = [];
    };

    script.onerror = function () {
      isLoadingFuse = false;
      console.error('[search] Failed to load Fuse.js from CDN');
      if (statusContainer) {
        statusContainer.textContent = 'Failed to load search library. Please try again later.';
      }
    };

    document.head.appendChild(script);
  }

  // --- Search Index ---

  /** Fetch the search index JSON */
  function fetchIndex(callback) {
    if (searchIndex.length > 0) {
      if (callback) callback(searchIndex);
      return;
    }

    var xhr = new XMLHttpRequest();
    xhr.open('GET', CONFIG.indexURL, true);
    xhr.onload = function () {
      if (xhr.status >= 200 && xhr.status < 400) {
        try {
          searchIndex = JSON.parse(xhr.responseText);
          if (callback) callback(searchIndex);
        } catch (e) {
          console.error('[search] Failed to parse search index:', e);
          setStatus('Error loading search data.');
        }
      } else {
        console.error('[search] Failed to fetch search index:', xhr.statusText);
        setStatus('Error loading search data.');
      }
    };
    xhr.onerror = function () {
      console.error('[search] Network error fetching search index');
      setStatus('Network error. Please try again.');
    };
    xhr.send();
  }

  // --- Fuse Initialization ---

  function initFuse(callback) {
    if (fuse) {
      if (callback) callback();
      return;
    }

    loadFuseJS(function () {
      fetchIndex(function (data) {
        fuse = new Fuse(data, {
          keys: CONFIG.fuseKeys,
          threshold: CONFIG.fuseThreshold,
          includeScore: true,
          minMatchCharLength: CONFIG.minChars,
        });

        if (callback) callback();
      });
    });
  }

  // --- Rendering ---

  function clearResults() {
    if (resultsContainer) {
      resultsContainer.innerHTML = '';
      resultsContainer.style.display = 'none';
    }
    activeIndex = -1;
    currentResults = [];
  }

  function setStatus(msg) {
    if (statusContainer) {
      statusContainer.textContent = msg;
      statusContainer.style.display = msg ? 'block' : 'none';
    }
  }

  function renderResults(results) {
    if (!resultsContainer) return;
    currentResults = results;
    activeIndex = -1;

    if (!results || results.length === 0) {
      resultsContainer.innerHTML = '';
      resultsContainer.style.display = 'none';
      return;
    }

    var html = '';
    for (var i = 0; i < results.length; i++) {
      var item = results[i].item || results[i];
      var snippet = item.summary ? item.summary.substring(0, 200) : '';
      html +=
        '<a href="' +
        item.permalink +
        '" class="cd-search-result" role="option" aria-selected="false" data-index="' +
        i +
        '">' +
        '<span class="cd-search-result-title">' +
        escapeHtml(item.title) +
        '</span>' +
        (snippet
          ? '<span class="cd-search-result-snippet">' + escapeHtml(snippet) + '</span>'
          : '') +
        '</a>';
    }

    resultsContainer.innerHTML = html;
    resultsContainer.style.display = 'block';
  }

  /** Simple HTML escaping */
  function escapeHtml(str) {
    if (!str) return '';
    var div = document.createElement('div');
    div.appendChild(document.createTextNode(str));
    return div.innerHTML;
  }

  // --- Searching ---

  /** Perform the actual search via Fuse */
  function doSearch(query) {
    var trimmed = query.trim();

    if (trimmed.length < CONFIG.minChars) {
      setStatus('Type at least ' + CONFIG.minChars + ' characters to search.');
      clearResults();
      return;
    }

    if (!fuse) return;

    var rawResults = fuse.search(trimmed);

    if (rawResults.length === 0) {
      setStatus('No results found for "' + trimmed + '".');
      clearResults();
      return;
    }

    setStatus('');
    renderResults(rawResults);
  }

  var debouncedSearch = debounce(function () {
    doSearch(input ? input.value : '');
  }, CONFIG.debounceMs);

  // --- Event Handlers ---

  function openSearch() {
    if (!overlay || !input) return;

    // Load Fuse and index only when search is first opened
    initFuse(function () {
      overlay.setAttribute('aria-hidden', 'false');
      overlay.setAttribute('data-visible', 'true');
      overlay.style.display = 'block';

      // Small delay so the overlay renders before focusing
      setTimeout(function () {
        input.focus();
      }, 50);

      // Re-run search if there's already a query
      if (input.value.trim().length >= CONFIG.minChars) {
        debouncedSearch();
      } else {
        setStatus('Type to search.');
      }
    });
  }

  function closeSearch() {
    if (!overlay) return;

    overlay.setAttribute('aria-hidden', 'true');
    overlay.setAttribute('data-visible', 'false');
    overlay.style.display = 'none';
    clearResults();
    setStatus('');
    if (input) input.value = '';

    // Return focus to trigger button
    var trigger = document.querySelector('.cd-search-trigger');
    if (trigger) trigger.focus();
  }

  function navigateResults(direction) {
    if (currentResults.length === 0) return;

    // Update active index
    activeIndex += direction;

    if (activeIndex < 0) {
      activeIndex = currentResults.length - 1;
    } else if (activeIndex >= currentResults.length) {
      activeIndex = 0;
    }

    // Update aria-selected on all results
    var items = resultsContainer.querySelectorAll('.cd-search-result');
    items.forEach(function (el, idx) {
      el.setAttribute('aria-selected', idx === activeIndex ? 'true' : 'false');
    });

    // Scroll into view
    var activeEl = items[activeIndex];
    if (activeEl) {
      activeEl.scrollIntoView({ block: 'nearest' });
    }
  }

  function activateCurrentResult() {
    if (activeIndex >= 0 && activeIndex < currentResults.length) {
      var items = resultsContainer.querySelectorAll('.cd-search-result');
      if (items[activeIndex]) {
        items[activeIndex].click();
      }
    }
  }

  // --- Keyboard Event Handler ---

  function onKeydown(e) {
    var isOpen = overlay && overlay.getAttribute('data-visible') === 'true';

    // Ctrl+K / Cmd+K — Toggle search
    if ((e.ctrlKey || e.metaKey) && e.key === 'k') {
      e.preventDefault();
      if (isOpen) {
        closeSearch();
      } else {
        openSearch();
      }
      return;
    }

    // / — Open search (only when not in text input and not already open)
    if (!isOpen && e.key === '/' && !isTextInput(e.target)) {
      // Don't prevent default in the case where we might be typing "/" in a URL bar
      // Actually, if we're not in a text input, "/" has no other purpose
      e.preventDefault();
      openSearch();
      return;
    }

    // When overlay is open
    if (isOpen) {
      // Escape — Close
      if (e.key === 'Escape') {
        e.preventDefault();
        closeSearch();
        return;
      }

      // ArrowUp — Navigate up
      if (e.key === 'ArrowUp') {
        e.preventDefault();
        navigateResults(-1);
        return;
      }

      // ArrowDown — Navigate down
      if (e.key === 'ArrowDown') {
        e.preventDefault();
        navigateResults(1);
        return;
      }

      // Enter — Activate selected result
      if (e.key === 'Enter') {
        // If a result is focused/selected via arrow keys, activate it
        if (activeIndex >= 0) {
          e.preventDefault();
          activateCurrentResult();
          return;
        }
        // Otherwise let default happen (no-op)
      }

      // Tab — Focus trap
      if (e.key === 'Tab') {
        var focusable = getFocusableElements();
        if (focusable.length === 0) return;

        var first = focusable[0];
        var last = focusable[focusable.length - 1];

        if (e.shiftKey) {
          // Shift+Tab: if first element is focused, wrap to last
          if (e.target === first) {
            e.preventDefault();
            last.focus();
          }
        } else {
          // Tab: if last element is focused, wrap to first
          if (e.target === last) {
            e.preventDefault();
            first.focus();
          }
        }
        return;
      }
    }
  }

  // --- Click / Trigger Handlers ---

  function onTriggerClick(e) {
    e.preventDefault();
    openSearch();
  }

  function onBackdropClick(e) {
    if (e.target && e.target.classList.contains('cd-search-backdrop')) {
      closeSearch();
    }
  }

  function onResultClick(e) {
    // The link click will navigate naturally, but we need to close the overlay
    var link = e.target.closest('.cd-search-result');
    if (link) {
      // Don't close immediately, let navigation happen first
      // Use a small timeout to close after navigation starts
      setTimeout(closeSearch, 100);
    }
  }

  // --- Result hover tracking ---

  function onResultMouseEnter(e) {
    var link = e.target.closest('.cd-search-result');
    if (!link) return;
    var idx = parseInt(link.getAttribute('data-index'), 10);
    if (!isNaN(idx)) {
      activeIndex = idx;
      // Update aria-selected on all results
      var items = resultsContainer.querySelectorAll('.cd-search-result');
      items.forEach(function (el, i) {
        el.setAttribute('aria-selected', i === idx ? 'true' : 'false');
      });
    }
  }

  // --- Input handler ---

  function onInput() {
    if (!input) return;
    var val = input.value;

    if (val.trim().length < CONFIG.minChars) {
      setStatus('Type at least ' + CONFIG.minChars + ' characters to search.');
      clearResults();
      return;
    }

    debouncedSearch();
  }

  // --- Initialization ---

  function init() {
    // No overlay rendered (feature disabled) → nothing to do
    if (!overlay || !input) return;

    // Ensure overlay starts hidden
    overlay.style.display = 'none';
    overlay.setAttribute('data-visible', 'false');
    overlay.setAttribute('aria-hidden', 'true');

    // Global keyboard listener
    document.addEventListener('keydown', onKeydown);

    // Trigger button
    var trigger = document.querySelector('.cd-search-trigger');
    if (trigger) {
      trigger.addEventListener('click', onTriggerClick);
    }

    // Close button
    if (closeBtn) {
      closeBtn.addEventListener('click', closeSearch);
    }

    // Backdrop click
    overlay.addEventListener('click', onBackdropClick);

    // Input events
    input.addEventListener('input', onInput);

    // Result click delegation
    if (resultsContainer) {
      resultsContainer.addEventListener('click', onResultClick);
      resultsContainer.addEventListener('mouseenter', onResultMouseEnter, true);
    }

    // Close on route change (SPA-like navigation via barba.js or similar)
    // For standard Hugo navigation, links will naturally navigate away.
  }

  // Boot
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', init);
  } else {
    init();
  }
})();
